import React from 'react';
import {creatorUpPost, creatorAddPost} from "../../1redux/postReducer.js";
import Post from "./post";
import {connect} from "react-redux";

let mapStateToProps = (state) => {
    return {
        postPage: state.post, 
    }
}
let mapDispatchToProps = (dispatch) => {
    return {
        addPost: () => {
            dispatch(creatorAddPost());
        },
        UpPost: (text ) => {
            dispatch(creatorUpPost(text ));
        }, 
    }
}

const containerPost = connect(mapStateToProps, mapDispatchToProps)(Post);

export default containerPost;
